changeSet.sql:
WITH grouped AS ( SELECT "correlationId" FROM public."reportData" WHERE "correlationId" IS NOT NULL GROUP BY "correlationId" HAVING COUNT(*) = 3 AND COUNT(DISTINCT "sourceSystem") = 1 AND COUNT(DISTINCT value) = 1 ),
master_records AS ( SELECT rd.* FROM public."reportData" rd JOIN grouped g ON rd."correlationId" = g."correlationId" WHERE rd."apValue" IS NOT NULL AND rd."arValue" IS NOT NULL )
UPDATE public."reportData" rd SET "debtType" = mr."debtType", "receivedInRequestEditor" = mr."receivedInRequestEditor", "enriched" = mr."enriched", "releasedFromRequestEditor" = mr."releasedFromRequestEditor" FROM master_records mr WHERE rd."correlationId" = mr."correlationId" AND rd."reportDataId" != mr."reportDataId" AND ( (rd."apValue" IS NOT NULL AND rd."arValue" IS NULL) OR (rd."arValue" IS NOT NULL AND rd."apValue" IS NULL) ) AND rd."sourceSystem" = mr."sourceSystem";
